using Microsoft.VisualStudio.TestTools.UnitTesting;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_ValidArgs_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 5);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_ValidArgs_CalculatesTotalPages()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 3);

            // Assert
            Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        }

        [TestMethod]
        public void Constructor_ValidArgs_AddsItemsToList()
        {
            // Arrange
            var items = new List<int> { 1, 2, 3 };

            // Act
            var list = new PaginatedList<int>(items, 10, 1, 5);

            // Assert
            Assert.AreEqual(3, list.Count);
            CollectionAssert.AreEqual(items, list);
        }

        [TestMethod]
        [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
        [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages")]
        [DataRow(1, 5, 1, DisplayName = "1 item, page size 5 = 1 page")]
        [DataRow(0, 5, 0, DisplayName = "0 items, page size 5 = 0 pages")]
        [DataRow(5, 5, 1, DisplayName = "5 items, page size 5 = 1 page")]
        [DataRow(100, 10, 10, DisplayName = "100 items, page size 10 = 10 pages")]
        public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Act & Assert
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Act & Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);

            // Act & Assert
            Assert.IsFalse(list.HasNextPage); // page 2 of 2
        }

        [TestMethod]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);

            // Act & Assert
            Assert.IsTrue(list.HasNextPage); // page 1 of 2
        }

        [TestMethod]
        public void HasNextPage_OnlyOnePage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 1, 1, 5);

            // Act & Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
