using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain the static queue to avoid cross-test interference
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            // Drain again after test
            var tempService = new NotificationService();
            while (tempService.ReceiveNotification() != null) { }
            tempService.Dispose();
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_CreatesCorrectMessage()
        {
            // Arrange & Act
            _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("admin", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsTrue(notification.Message.Contains("Student 'John Doe'"));
            Assert.IsTrue(notification.Message.Contains("created"));
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            // Act
            _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "system");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains("Course (ID: 42)"));
            Assert.IsTrue(notification.Message.Contains("updated"));
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            // Act
            _sut.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
            Assert.IsTrue(notification.Message.Contains("deleted"));
        }

        [TestMethod]
        public void SendNotification_DefaultUserName_SetsSystemAsCreatedBy()
        {
            // Act
            _sut.SendNotification("Student", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
        {
            // Arrange
            _sut.SendNotification("A", "1", EntityOperation.CREATE);
            _sut.SendNotification("B", "2", EntityOperation.UPDATE);
            _sut.SendNotification("C", "3", EntityOperation.DELETE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.AreEqual("A", first.EntityType);

            var second = _sut.ReceiveNotification();
            Assert.AreEqual("B", second.EntityType);

            var third = _sut.ReceiveNotification();
            Assert.AreEqual("C", third.EntityType);

            Assert.IsNull(_sut.ReceiveNotification());
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - should be a no-op for in-memory implementation
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(0);
            _sut.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert
            _sut.Dispose();
            _sut.Dispose(); // Double dispose should be safe
        }

        [TestMethod]
        public void SendNotification_CreatedAt_IsSetToCurrentTime()
        {
            // Arrange
            var before = System.DateTime.Now.AddSeconds(-1);

            // Act
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);

            // Assert
            var after = System.DateTime.Now.AddSeconds(1);
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before && notification.CreatedAt <= after);
        }

        [TestMethod]
        public void SendNotification_IsRead_DefaultsFalse()
        {
            // Act
            _sut.SendNotification("Test", "1", EntityOperation.CREATE);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "created", DisplayName = "CREATE message")]
        [DataRow(EntityOperation.UPDATE, "updated", DisplayName = "UPDATE message")]
        [DataRow(EntityOperation.DELETE, "deleted", DisplayName = "DELETE message")]
        public void SendNotification_DifferentOperations_GeneratesCorrectVerb(EntityOperation operation, string expectedVerb)
        {
            // Act
            _sut.SendNotification("Entity", "1", "TestName", operation);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.Message.Contains(expectedVerb),
                $"Expected message to contain '{expectedVerb}', got: {notification.Message}");
        }
    }
}

