using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    // Concrete subclass to test protected BaseController methods
    public class TestableBaseController : BaseController
    {
        public TestableBaseController(SchoolContext context) : base(context)
        {
        }

        public void CallSendEntityNotification(string entityType, string entityId, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, operation);
        }

        public void CallSendEntityNotification(string entityType, string entityId, string displayName, EntityOperation operation)
        {
            SendEntityNotification(entityType, entityId, displayName, operation);
        }

        public new void Dispose(bool disposing)
        {
            base.Dispose(disposing);
        }
    }

    [TestClass]
    public sealed class BaseControllerTests
    {
        private SchoolContext _context;
        private TestableBaseController _controller;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.Create();
            _controller = new TestableBaseController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void SendEntityNotification_WithoutDisplayName_DoesNotThrow()
        {
            // Act & Assert - should not throw even if notification service is active
            _controller.CallSendEntityNotification("Student", "1", EntityOperation.CREATE);
        }

        [TestMethod]
        public void SendEntityNotification_WithDisplayName_DoesNotThrow()
        {
            // Act & Assert
            _controller.CallSendEntityNotification("Course", "42", "Chemistry", EntityOperation.UPDATE);
        }

        [TestMethod]
        public void SendEntityNotification_DeleteOperation_DoesNotThrow()
        {
            // Act & Assert
            _controller.CallSendEntityNotification("Department", "5", "Engineering", EntityOperation.DELETE);
        }

        [TestMethod]
        public void Dispose_WithTrue_DisposesResources()
        {
            // Act & Assert - should not throw
            _controller.Dispose(true);
        }

        [TestMethod]
        public void Dispose_WithFalse_DoesNotThrow()
        {
            // Act & Assert - should not throw
            _controller.Dispose(false);
        }

        [TestMethod]
        public void Constructor_SetsDbContext()
        {
            // Assert
            Assert.IsNotNull(_controller);
        }

        [TestMethod]
        public void BaseController_InheritsFromController()
        {
            // Assert
            Assert.IsInstanceOfType<Controller>(_controller);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, DisplayName = "CREATE notification")]
        [DataRow(EntityOperation.UPDATE, DisplayName = "UPDATE notification")]
        [DataRow(EntityOperation.DELETE, DisplayName = "DELETE notification")]
        public void SendEntityNotification_AllOperations_DoNotThrow(EntityOperation operation)
        {
            // Act & Assert - all operations should succeed silently
            _controller.CallSendEntityNotification("Test", "1", "TestName", operation);
        }
    }
}

